```cpp
#include <iostream>
#include <random>

int main() {
    // Create a random number generator
    std::random_device rd;
    std::mt19937 gen(rd());
    std::uniform_int_distribution<> dis(1, 3);

    // Generate random choices
    int playerChoice = dis(gen);
    int computerChoice = dis(gen);

    // Determine the winner
    if (playerChoice == computerChoice) {
        std::cout << "It's a tie!" << std::endl;
    } else if ((playerChoice == 1 && computerChoice == 3) ||
               (playerChoice == 2 && computerChoice == 1) ||
               (playerChoice == 3 && computerChoice == 2)) {
        std::cout << "You win!" << std::endl;
    } else {
        std::cout << "Computer wins!" << std::endl;
    }

    return 0;
}
```
This code is like a mini-game – it generates random choices, determines the winner, and displays the result. It's a fun example of how C++ can be used to create interactive programs.

